import React from 'react';
import './AboutPage.css';

const AboutPage = () => {
  const handleSocialMediaClick = (platform) => {
    let url;
    switch (platform) {
      case 'instagram':
        url = 'https://www.instagram.com/jeenas.kitchen/reels/';
        break;
      case 'youtube':
        url = 'https://www.youtube.com/@Jeena.s.kitchen';
        break;
      default:
        return;
    }
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  const handleVideoClick = (videoUrl) => {
    window.open(videoUrl, '_blank', 'noopener,noreferrer');
  };

  const handleInstagramPostClick = (postUrl) => {
    window.open(postUrl, '_blank', 'noopener,noreferrer');
  };

  // Instagram reel data with custom thumbnails
  const instagramReels = [
    {
      id: 'C-5Pb10h-WQ',
      url: 'https://www.instagram.com/reel/C-5Pb10h-WQ/',
      thumbnail: '/modal-images/samgak-gimbap.jpg',
      title: 'Samgak Gimbap',
      description: 'Quick and easy triangular gimbap'
    },
    {
      id: 'C93-oOxx_yP', 
      url: 'https://www.instagram.com/p/C93-oOxx_yP/',
      thumbnail: '/modal-images/potato-salada-sandwich.jpg',
      title: 'Potato Salad Sandwich',
      description: 'Creamy potato salad sandwich'
    },
    {
